 * - Les headers par défaut
 * - La gestion des erreurs
 * - La gestion des tokens d'authentification
 */
const api = axios.create({
    // URL de base de l'API Laravel depuis la configuration
    baseURL: config.api.baseURL,

    // Headers par défaut
    headers: {
        // Ne pas fixer Content-Type globalement pour permettre le multipart/form-data lors des uploads
        'Accept': 'application/json',
    },

    // Timeout depuis la configuration
    timeout: config.api.timeout,
});

/**
 * Intercepteur pour ajouter le token d'authentification
 * 
 * Cet intercepteur ajoute automatiquement le token JWT
 * à toutes les requêtes si il existe dans le localStorage
 */
api.interceptors.request.use(
    (config) => {
        const token = localStorage.getItem('token');
        if (token) {
            config.headers.Authorization = `Bearer ${token}`;
        }
        return config;
    },
    (error) => {
        return Promise.reject(error);
    }
);

/**
 * Intercepteur pour gérer les erreurs de réponse
 * 
 * Cet intercepteur gère :
 * - Les erreurs 401 (non authentifié)
 * - Les erreurs 403 (accès refusé)
 * - Les erreurs de réseau
 * - La redirection vers la page de connexion si nécessaire
 */
api.interceptors.response.use(
    (response) => {
        // Validation de la réponse
        if (!response.data) {
            throw new Error('Réponse invalide du serveur');
        }
        return response;
    },
    (error) => {
        // Gestion des erreurs d'authentification
        if (error.response?.status === 401) {
            localStorage.removeItem('token');
            localStorage.removeItem('user');
            // Utiliser window.location.href au lieu de router.push pour éviter les erreurs
            if (window.location.pathname !== '/login') {
                window.location.href = '/login';
            }
        }

        // Gestion des erreurs d'accès refusé
        if (error.response?.status === 403) {
            console.error('Accès refusé:', error.response.data.message);
        }

        // Gestion des erreurs de validation
        if (error.response?.status === 422) {
            const validationErrors = error.response.data.errors;
            if (validationErrors) {
                const errorMessage = Object.values(validationErrors).flat().join(', ');
                error.message = `Erreur de validation: ${errorMessage}`;
            }
        }

        // Gestion des erreurs de réseau
        if (!error.response) {
            error.message = 'Erreur de connexion au serveur. Vérifiez votre connexion internet.';
        }

        // Gestion des erreurs 500+
        if (error.response?.status >= 500) {
            error.message = 'Erreur interne du serveur. Veuillez réessayer plus tard.';
        }

        return Promise.reject(error);
    }
);

// ============================================================================
// ROUTES D'AUTHENTIFICATION
// ============================================================================

